const answer = $input.first().json.output || '';
return [{ json: { status: 'success', ticker, question, answer, retrievalSource: 'financial_rag_' + ticker, model: 'gpt-4o', embeddingModel: 'text-embedding-3-small', faithfulnessTarget: '>90%', timestamp: new Date().toISOString() } }];
